INSERT INTO public.speaking_tasks (topic, level, sort_order, uz_text, ru_correct) VALUES
('tanishuv', 'A1', 1, 'Mening ismim Ali.', 'Меня зовут Али.'),
('tanishuv', 'A1', 2, 'Men O‘zbekistondan kelganman.', 'Я приехал из Узбекистана.'),
('tanishuv', 'A1', 3, 'Siz bilan tanishganimdan xursandman.', 'Рад с вами познакомиться.'),
('tanishuv', 'A1', 4, 'Bu mening do‘stim Jamshid.', 'Это мой друг Жамшид.'),
('tanishuv', 'A1', 5, 'Qayerliksiz?', 'Откуда вы?'),
('tanishuv', 'A1', 6, 'Men 25 yoshdaman.', 'Мне 25 лет.'),
('tanishuv', 'A1', 7, 'Men talabaman.', 'Я студент.'),
('tanishuv', 'A1', 8, 'U mening ukam.', 'Это мой младший брат.'),
('tanishuv', 'A1', 9, 'Sizning ismingiz nima?', 'Как вас зовут?'),
('tanishuv', 'A1', 10, 'Men rus tilini o‘rganyapman.', 'Я учу русский язык.'),
('tanishuv', 'A1', 11, 'Qandaysiz?', 'Как дела?'),
('tanishuv', 'A1', 12, 'Yaxshi, rahmat.', 'Хорошо, спасибо.'),
('tanishuv', 'A1', 13, 'U qayerda ishlaydi?', 'Где он работает?'),
('tanishuv', 'A1', 14, 'Bu mening sinfdoshim.', 'Это мой одноклассник.'),
('tanishuv', 'A1', 15, 'Men Toshkentda yashayman.', 'Я живу в Ташкенте.'),
('tanishuv', 'A1', 16, 'Siz bilan tanishganimdan baxtiyorman.', 'Счастлив познакомиться с вами.'),
('tanishuv', 'A1', 17, 'U kelgan mamlakat – Rossiya. – Страна, откуда он приехал', 'Россия.'),
('tanishuv', 'A1', 18, 'Biz bir guruhdamiz.', 'Мы в одной группе.'),
('tanishuv', 'A1', 19, 'Kechirasiz, sizni tushunmadim.', 'Извините, я вас не понял.'),
('tanishuv', 'A1', 20, 'Yana ko‘rishguncha!', 'До свидания!'),
('oila', 'A1', 1, 'Mening oilam katta.', 'Моя семья большая.'),
('oila', 'A1', 2, 'Onam shifokor.', 'Моя мама врач.'),
('oila', 'A1', 3, 'Akam muhandis.', 'Мой старший брат инженер.'),
('oila', 'A1', 4, 'Biz bir uyda yashaymiz.', 'Мы живём в одном доме.'),
('oila', 'A1', 5, 'Mening singlim bor.', 'У меня есть младшая сестра.'),
('oila', 'A1', 6, 'Otam ishlaydi.', 'Мой папа работает.'),
('oila', 'A1', 7, 'Bobom va buvim qishloqda yashaydi.', 'Дедушка и бабушка живут в деревне.'),
('oila', 'A1', 8, 'Mening ikki akam bor.', 'У меня два брата.'),
('oila', 'A1', 9, 'Opam universitetda o‘qiydi.', 'Моя старшая сестра учится в университете.'),
('oila', 'A1', 10, 'Biz har yakshanba birga ovqatlanamiz.', 'Каждое воскресенье мы едим вместе.'),
('oila', 'A1', 11, 'Mening katta oilam bor.', 'У меня большая семья.'),
('oila', 'A1', 12, 'U mening amakivachcham.', 'Это мой двоюродный брат.'),
('oila', 'A1', 13, 'Qaynonam mehribon.', 'Моя свекровь добрая.'),
('oila', 'A1', 14, 'Kuyovim muhandis.', 'Мой зять инженер.'),
('oila', 'A1', 15, 'Kelinim chiroyli.', 'Моя невестка красивая.'),
('oila', 'A1', 16, 'Farzandlarim maktabda o‘qiydi.', 'Мои дети учатся в школе.'),
('oila', 'A1', 17, 'Erim kecha ishdan kech keldi.', 'Мой муж вчера пришёл с работы поздно.'),
('oila', 'A1', 18, 'Xotinim non pishirdi.', 'Моя жена испекла хлеб.'),
('oila', 'A1', 19, 'Oilam men uchun eng muhimi.', 'Семья для меня самое важное.'),
('oila', 'A1', 20, 'Biz bir-birimizni sevamiz.', 'Мы любим друг друга.'),
('uy_joy', 'A1', 1, 'Uyimiz kichik, lekin qulay.', 'Наш дом маленький, но уютный.'),
('uy_joy', 'A1', 2, 'Xonamda stol va kompyuter bor.', 'В моей комнате есть стол и компьютер.'),
('uy_joy', 'A1', 3, 'Oshxona toza.', 'Кухня чистая.'),
('uy_joy', 'A1', 4, 'Hovlida gulzor bor.', 'Во дворе есть цветник.'),
('uy_joy', 'A1', 5, 'Qo‘shnilarim yaxshi odamlar.', 'Мои соседи хорошие люди.'),
('uy_joy', 'A1', 6, 'Yotoqxonamda katta karavot bor.', 'В моей спальне большая кровать.'),
('uy_joy', 'A1', 7, 'Tom ostidagi xona – bolalar xonasi. – Комната под крышей', 'детская.'),
('uy_joy', 'A1', 8, 'Bizning uyda uch xona bor.', 'В нашем доме три комнаты.'),
('uy_joy', 'A1', 9, 'Hammom va hojatxona alohida.', 'Ванная и туалет раздельные.'),
('uy_joy', 'A1', 10, 'Derazadan bog‘ ko‘rinadi.', 'Из окна виден сад.'),
('uy_joy', 'A1', 11, 'Uyning yonida garaj bor.', 'Рядом с домом есть гараж.'),
('uy_joy', 'A1', 12, 'Kiraverishda katta yo‘lak bor.', 'У входа есть большой коридор.'),
('uy_joy', 'A1', 13, 'Mehmonxona yorug‘ va keng.', 'Гостиная светлая и просторная.'),
('uy_joy', 'A1', 14, 'Mening uyim shaharning markazida.', 'Мой дом в центре города.'),
('uy_joy', 'A1', 15, 'Ijarada yashayman.', 'Я живу в арендованной квартире.'),
('uy_joy', 'A1', 16, 'Kommunal to‘lovlar qimmat.', 'Коммунальные платежи дорогие.'),
('uy_joy', 'A1', 17, 'Eshik qulflanganmi?', 'Дверь заперта?'),
('uy_joy', 'A1', 18, 'Kalitni stol ustiga qo‘ying.', 'Положите ключ на стол.'),
('uy_joy', 'A1', 19, 'Uyda muzlatgich va kir yuvish mashinasi bor.', 'Дома есть холодильник и стиральная машина.'),
('uy_joy', 'A1', 20, 'Biz yangi uy sotib oldik.', 'Мы купили новый дом.'),
('shahar', 'A1', 1, 'Shahrimiz go‘zal.', 'Наш город красивый.'),
('shahar', 'A1', 2, 'Sariq taksi bu yerda arzon.', 'Жёлтое такси здесь дешёвое.'),
('shahar', 'A1', 3, 'Metro bekati uzoq emas.', 'Станция метро недалеко.'),
('shahar', 'A1', 4, 'Ko‘chada ko‘p odam bor.', 'На улице много людей.'),
('shahar', 'A1', 5, 'Men adashib qoldim.', 'Я заблудился.'),
('shahar', 'A1', 6, 'Bu maydon juda katta.', 'Эта площадь очень большая.'),
('shahar', 'A1', 7, 'Favvora kechasi yoritilgan.', 'Фонтан подсвечен ночью.'),
('shahar', 'A1', 8, 'Shaharda bog‘lar va istirohat bog‘lari bor.', 'В городе есть парки и скверы.'),
('shahar', 'A1', 9, 'Kecha biz kinoteatrga bordik.', 'Вчера мы ходили в кинотеатр.'),
('shahar', 'A1', 10, 'Sirk yaqinida ko‘prik bor.', 'Возле цирка есть мост.'),
('shahar', 'A1', 11, 'Ko‘chani kesib o‘tishdan oldin svetoforga qarang.', 'Прежде чем перейти улицу, посмотрите на светофор.'),
('shahar', 'A1', 12, 'Piyodalar yo‘lagi qayerda?', 'Где пешеходная дорожка?'),
('shahar', 'A1', 13, 'Bu yerda to‘xtash mumkin emas.', 'Здесь нельзя останавливаться.'),
('shahar', 'A1', 14, 'Eng yaqin dorixona qayerda?', 'Где ближайшая аптека?'),
('shahar', 'A1', 15, 'Shahar markaziga avtobusda borish mumkin.', 'В центр города можно доехать на автобусе.'),
('shahar', 'A1', 16, 'Kechqurun ko‘chalar yorug‘.', 'Вечером улицы освещены.'),
('shahar', 'A1', 17, 'Men bu shaharda o‘sganman.', 'Я вырос в этом городе.'),
('shahar', 'A1', 18, 'Bu joy juda shovqinli.', 'Это место очень шумное.'),
('shahar', 'A1', 19, 'Shaharda iflos havo muammosi bor.', 'В городе есть проблема грязного воздуха.'),
('shahar', 'A1', 20, 'Men shahar hayotini yaxshi ko‘raman.', 'Мне нравится городская жизнь.'),
('xarid', 'A1', 1, 'Bir kilogramm olma bering.', 'Дайте один килограмм яблок.'),
('xarid', 'A1', 2, 'Qancha turadi?', 'Сколько стоит?'),
('xarid', 'A1', 3, 'Bu juda qimmat.', 'Это слишком дорого.'),
('xarid', 'A1', 4, 'Karta bilan to‘layman.', 'Я заплачу картой.'),
('xarid', 'A1', 5, 'Sizda non bormi?', 'У вас есть хлеб?'),
('xarid', 'A1', 6, 'Menga bir litr sut kerak.', 'Мне нужен один литр молока.'),
('xarid', 'A1', 7, 'Bu kiyimni sinab ko‘rish mumkinmi?', 'Можно примерить эту одежду?'),
('xarid', 'A1', 8, 'Sizda mayda pul bormi?', 'У вас есть мелкие деньги?'),
('xarid', 'A1', 9, 'Chekni olishim mumkinmi?', 'Могу я получить чек?'),
('xarid', 'A1', 10, 'Bu mahsulot chegirmadami?', 'Этот товар со скидкой?'),
('xarid', 'A1', 11, 'Qayerda go‘sht bo‘limi?', 'Где мясной отдел?'),
('xarid', 'A1', 12, 'Sabzavotlar yangimi?', 'Овощи свежие?'),
('xarid', 'A1', 13, 'Men faqat ko‘rish uchun keldim.', 'Я пришёл просто посмотреть.'),
('xarid', 'A1', 14, 'Sizda o‘lcham 38 bormi?', 'У вас есть размер 38?'),
('xarid', 'A1', 15, 'Rang yoqmay qoldi.', 'Цвет не понравился.'),
('xarid', 'A1', 16, 'Bu sovg‘a uchun qadoqlanganmi?', 'Это упаковано для подарка?'),
('xarid', 'A1', 17, 'Sotuvchi juda muloyim.', 'Продавец очень вежливый.'),
('xarid', 'A1', 18, 'Do‘kon soat 9 da yopiladi.', 'Магазин закрывается в 9 часов.'),
('xarid', 'A1', 19, 'Kechirasiz, navbat kimda?', 'Извините, чья очередь?'),
('xarid', 'A1', 20, 'Bugun katta savdo bor.', 'Сегодня большая распродажа.'),
('ovqat_ichimlik', 'A1', 1, 'Men choy ichaman.', 'Я пью чай.'),
('ovqat_ichimlik', 'A1', 2, 'Osh juda mazali.', 'Плов очень вкусный.'),
('ovqat_ichimlik', 'A1', 3, 'Non va qaymoq bering.', 'Дайте хлеб и сметану.'),
('ovqat_ichimlik', 'A1', 4, 'Men go‘sht yemayman.', 'Я не ем мясо.'),
('ovqat_ichimlik', 'A1', 5, 'Suv sovuq.', 'Вода холодная.'),
('ovqat_ichimlik', 'A1', 6, 'Nonushtaga nima yeysiz?', 'Что вы едите на завтрак?'),
('ovqat_ichimlik', 'A1', 7, 'Men tuxum va pishloqni yaxshi ko‘raman.', 'Я люблю яйца и сыр.'),
('ovqat_ichimlik', 'A1', 8, 'Sho‘rva issiq.', 'Суп горячий.'),
('ovqat_ichimlik', 'A1', 9, 'Kofe shakarsiz, iltimos.', 'Кофе без сахара, пожалуйста.'),
('ovqat_ichimlik', 'A1', 10, 'Sizda vegetarian taomlari bormi?', 'У вас есть вегетарианские блюда?'),
('ovqat_ichimlik', 'A1', 11, 'Men olma sharbatini xohlayman.', 'Я хочу яблочный сок.'),
('ovqat_ichimlik', 'A1', 12, 'Kek juda shirin.', 'Пирожное слишком сладкое.'),
('ovqat_ichimlik', 'A1', 13, 'Tuzni uzating.', 'Передайте соль.'),
('ovqat_ichimlik', 'A1', 14, 'Baliq yangi emas.', 'Рыба несвежая.'),
('ovqat_ichimlik', 'A1', 15, 'Men to‘ymadim.', 'Я не наелся.'),
('ovqat_ichimlik', 'A1', 16, 'Yana bir bo‘lak non olaman.', 'Возьму ещё кусок хлеба.'),
('ovqat_ichimlik', 'A1', 17, 'Ovqat tayyor.', 'Еда готова.'),
('ovqat_ichimlik', 'A1', 18, 'Kechki ovqatga makaron qaynatamiz.', 'На ужин сварим макароны.'),
('ovqat_ichimlik', 'A1', 19, 'Muzqaymoqni yoqtiraman.', 'Я люблю мороженое.'),
('ovqat_ichimlik', 'A1', 20, 'Meva-sabzavotlarni yuvish kerak.', 'Фрукты и овощи нужно мыть.'),
('ish_sodda', 'A1', 1, 'Men o‘qituvchiman.', 'Я учитель.'),
('ish_sodda', 'A1', 2, 'U haydovchi bo‘lib ishlaydi.', 'Он работает водителем.'),
('ish_sodda', 'A1', 3, 'Ish soat 9 da boshlanadi.', 'Работа начинается в 9 часов.'),
('ish_sodda', 'A1', 4, 'Mening maoshim yaxshi.', 'У меня хорошая зарплата.'),
