('kundalik_harakatlar', 'A1', 8, 'Avtobusga chiqaman.', 'Сажусь в автобус.'),
('kundalik_harakatlar', 'A1', 9, 'Ishda kompyuterda yozaman.', 'На работе печатаю на компьютере.'),
