('fikr_va_dalil_b1', 'B1', 17, 'Statistik ma’lumotlar aksini ko‘rsatadi.', 'Статистические данные показывают обратное.'),
('fikr_va_dalil_b1', 'B1', 18, 'Insonlar ko‘pincha his-tuyg‘ulariga asoslanib qaror qabul qilishadi.', 'Люди часто принимают решения, основываясь на эмоциях.'),
('fikr_va_dalil_b1', 'B1', 19, 'Men o‘z fikrimni himoya qilishga tayyorman.', 'Я готов защищать своё мнение.'),
('fikr_va_dalil_b1', 'B1', 20, 'Ob’ektiv bo‘lishga harakat qiling.', 'Постарайтесь быть объективным.'),
('muloqot_odamlar_b1', 'B1', 1, 'Odamlar bilan umumiy til topish muhim.', 'Важно находить общий язык с людьми.'),
('muloqot_odamlar_b1', 'B1', 2, 'U juda xushmuomala va yordamga tayyor.', 'Он очень вежливый и готов помочь.'),
('muloqot_odamlar_b1', 'B1', 3, 'Kechirim so‘rashdan uyalmang.', 'Не стесняйтесь извиняться.'),
('muloqot_odamlar_b1', 'B1', 4, 'U bilan gaplashish yoqimli.', 'С ним приятно разговаривать.'),
('muloqot_odamlar_b1', 'B1', 5, 'Konfliktni tinch yo‘l bilan hal qilish kerak.', 'Конфликт нужно решать мирным путём.'),
('muloqot_odamlar_b1', 'B1', 6, 'Yaxshi tinglovchi bo‘lish – san’at. – Быть хорошим слушателем', 'искусство.'),
('muloqot_odamlar_b1', 'B1', 7, 'U har doim gapni bo‘lib qo‘yadi.', 'Он всегда перебивает.'),
('muloqot_odamlar_b1', 'B1', 8, 'Begona odam bilan suhbatni qanday boshlash kerak?', 'Как начать разговор с незнакомцем?'),
('muloqot_odamlar_b1', 'B1', 9, 'U menga sovuq muomala qilmoqda.', 'Он ведёт себя со мной холодно.'),
('muloqot_odamlar_b1', 'B1', 10, 'Men odamlarning kayfiyatini his qilaman.', 'Я чувствую настроение людей.'),
('muloqot_odamlar_b1', 'B1', 11, 'Yolg‘on gapirish munosabatlarga putur yetkazadi.', 'Ложь вредит отношениям.'),
('muloqot_odamlar_b1', 'B1', 12, 'U juda kamtar va ochiq.', 'Он очень скромный и открытый.'),
('muloqot_odamlar_b1', 'B1', 13, 'Katta guruhda gaplashish menga qiyin.', 'Мне трудно говорить в большой группе.'),
('muloqot_odamlar_b1', 'B1', 14, 'Siz bilan gaplashish menga yoqadi.', 'Мне нравится с вами разговаривать.'),
('muloqot_odamlar_b1', 'B1', 15, 'Biz bir-birimizga hazil qilamiz.', 'Мы шутим друг над другом.'),
('muloqot_odamlar_b1', 'B1', 16, 'U doim yordam taklif qiladi.', 'Он всегда предлагает помощь.'),
('muloqot_odamlar_b1', 'B1', 17, 'Men odamlarning ko‘ziga qarab gapirishga harakat qilaman.', 'Стараюсь говорить людям в глаза.'),
('muloqot_odamlar_b1', 'B1', 18, 'Yomon kayfiyatingizni boshqalarga chiqarmang.', 'Не вымещайте плохое настроение на других.'),
('muloqot_odamlar_b1', 'B1', 19, 'Biz muntazam ravishda telefon orqali gaplashib turamiz.', 'Мы регулярно разговариваем по телефону.'),
('muloqot_odamlar_b1', 'B1', 20, 'Ijtimoiy tarmoqlarda muloqot jonli muloqot o‘rnini bosa olmaydi.', 'Общение в соцсетях не заменит живого общения.'),
('muammo_yechim_b1', 'B1', 1, 'Mening kompyuterim ishlamayapti.', 'Мой компьютер не работает.'),
('muammo_yechim_b1', 'B1', 2, 'Elektr uzilib qoldi.', 'Отключили электричество.'),
('muammo_yechim_b1', 'B1', 3, 'Internet tezligi juda past.', 'Скорость интернета очень низкая.'),
('muammo_yechim_b1', 'B1', 4, 'Buning bir necha yechimi bor.', 'Есть несколько решений этого.'),
('muammo_yechim_b1', 'B1', 5, 'Mutaxassisni chaqirish kerak.', 'Нужно вызвать специалиста.'),
('muammo_yechim_b1', 'B1', 6, 'Muzlatgichdan suv oqmoqda.', 'Из холодильника течёт вода.'),
('muammo_yechim_b1', 'B1', 7, 'Viza muddati tugayapti, uzaytirish kerak.', 'Заканчивается виза, нужно продлить.'),
('muammo_yechim_b1', 'B1', 8, 'Biznesda muammolar yuzaga keldi.', 'В бизнесе возникли проблемы.'),
('muammo_yechim_b1', 'B1', 9, 'Qisqa vaqt ichida qaror qabul qilishim kerak.', 'Мне нужно принять решение за короткое время.'),
('muammo_yechim_b1', 'B1', 10, 'Muammoni e’tiborsiz qoldirish mumkin emas.', 'Нельзя игнорировать проблему.'),
('muammo_yechim_b1', 'B1', 11, 'Birgalikda yechim topish osonroq.', 'Вместе легче найти решение.'),
('muammo_yechim_b1', 'B1', 12, 'Eng yomoni shundaki, biz hech narsa qilmaymiz.', 'Хуже всего то, что мы ничего не делаем.'),
('muammo_yechim_b1', 'B1', 13, 'U har qanday muammodan chiqish yo‘lini topadi.', 'Он находит выход из любой проблемы.'),
('muammo_yechim_b1', 'B1', 14, 'Moliyaviy qiyinchiliklar bizni to‘xtata olmaydi.', 'Финансовые трудности не могут нас остановить.'),
('muammo_yechim_b1', 'B1', 15, 'Kechirasiz, bu sizning muammoingiz emas.', 'Извините, это не ваша проблема.'),
('muammo_yechim_b1', 'B1', 16, 'Qarama-qarshilikni konstruktiv hal qilish mumkin.', 'Противопоставление можно решить конструктивно.'),
('muammo_yechim_b1', 'B1', 17, 'Kechikishlar jiddiy muammoga aylandi.', 'Опоздания стали серьёзной проблемой.'),
('muammo_yechim_b1', 'B1', 18, 'Eng yaxshi yechim – oldini olish. – Лучшее решение', 'профилактика.'),
('muammo_yechim_b1', 'B1', 19, 'U o‘z muammolari haqida gapirishni yoqtirmaydi.', 'Он не любит говорить о своих проблемах.'),
('muammo_yechim_b1', 'B1', 20, 'Vaqt o‘tishi bilan muammo o‘z-o‘zidan hal bo‘ladi.', 'Со временем проблема решится сама собой.'),
('kochish_b1', 'B1', 1, 'Men boshqa shaharga ko‘chib o‘tdim.', 'Я переехал в другой город.'),
('kochish_b1', 'B1', 2, 'Yangi joyga moslashish qiyin.', 'Трудно привыкнуть к новому месту.'),
('kochish_b1', 'B1', 3, 'Mahalliy tilni o‘rganish kerak.', 'Нужно выучить местный язык.'),
('kochish_b1', 'B1', 4, 'Viza muddatini uzaytirish mumkinmi?', 'Можно продлить визу?'),
('kochish_b1', 'B1', 5, 'Vatanimni sog‘indim.', 'Я скучаю по родине.'),
('kochish_b1', 'B1', 6, 'Boshqa mamlakatda yashash dunyoqarashni kengaytiradi.', 'Жизнь в другой стране расширяет кругозор.'),
('kochish_b1', 'B1', 7, 'Men hujjatlarni rasmiylashtirish uchun ko‘p vaqt sarfladim.', 'Я потратил много времени на оформление документов.'),
('kochish_b1', 'B1', 8, 'Yashash joyini tanlashda maktab va infratuzilma muhim.', 'При выборе места жительства важны школа и инфраструктура.'),
('kochish_b1', 'B1', 9, 'U chet elda ishlash taklifini qabul qildi.', 'Он принял предложение работать за границей.'),
('kochish_b1', 'B1', 10, 'Madaniy farqlar tufayli tushunmovchiliklar yuz berdi.', 'Из-за культурных различий возникло недопонимание.'),
('kochish_b1', 'B1', 11, 'Men ijara haqini to‘lashga qiynalayapman.', 'Мне трудно платить арендную плату.'),
('kochish_b1', 'B1', 12, 'Qo‘shnilar bilan til topishish ba’zan qiyin.', 'С соседями иногда трудно найти общий язык.'),
('kochish_b1', 'B1', 13, 'Chet elda o‘qishga grant yutib oldim.', 'Я выиграл грант на учёбу за границей.'),
('kochish_b1', 'B1', 14, 'Vaqt o‘tishi bilan yangi joyni o‘z uyimdek his qila boshladim.', 'Со временем я начал чувствовать новое место как свой дом.'),
('kochish_b1', 'B1', 15, 'Ko‘chib o‘tish stressli, lekin qiziqarli tajriba. – Переезд', 'это стрессовый, но интересный опыт.'),
('kochish_b1', 'B1', 16, 'Men har yili vatanimga qaytib boraman.', 'Я каждый год возвращаюсь на родину.'),
('kochish_b1', 'B1', 17, 'Chet ellik sifatida mahalliy qonunlarni bilishim kerak.', 'Как иностранец, я должен знать местные законы.'),
('kochish_b1', 'B1', 18, 'Dastlab til bilmaslik katta muammo edi.', 'Сначала незнание языка было большой проблемой.'),
('kochish_b1', 'B1', 19, 'Biz yangi mamlakatda o‘z biznesimizni ochdik.', 'Мы открыли свой бизнес в новой стране.'),
('kochish_b1', 'B1', 20, 'Ko‘chib o‘tishdan oldin batafsil tadqiqot qilish kerak.', 'Перед переездом нужно провести детальное исследование.'),
('hujjatlar_b1', 'B1', 1, 'Pasportim muddati tugagan.', 'У меня истёк срок паспорта.'),
('hujjatlar_b1', 'B1', 2, 'Anketa to‘ldirish kerak.', 'Нужно заполнить анкету.'),
('hujjatlar_b1', 'B1', 3, 'Sertifikatning nusxasini oling.', 'Сделайте копию сертификата.'),
('hujjatlar_b1', 'B1', 4, 'Hujjatlar notariusda tasdiqlanishi kerak.', 'Документы должны быть заверены нотариусом.'),
('hujjatlar_b1', 'B1', 5, 'Fuqarolikni olish jarayoni uzoq.', 'Процесс получения гражданства долгий.'),
('hujjatlar_b1', 'B1', 6, 'Men tug‘ilganlik haqidagi guvohnomani yo‘qotib qo‘ydim.', 'Я потерял свидетельство о рождении.'),
('hujjatlar_b1', 'B1', 7, 'Ariza ikki nusxada topshiriladi.', 'Заявление подаётся в двух экземплярах.'),
('hujjatlar_b1', 'B1', 8, 'Mening diplomim nostrifikatsiyadan o‘tishi kerak.', 'Мой диплом должен пройти нострификацию.'),
('hujjatlar_b1', 'B1', 9, 'Chet el pasporti uchun fotosurat kerak.', 'Для загранпаспорта нужна фотография.'),
('hujjatlar_b1', 'B1', 10, 'Hujjatlarni topshirishdan oldin tekshiring.', 'Перед подачей проверьте документы.'),
('hujjatlar_b1', 'B1', 11, 'Ko‘p funktsiyali markazga murojaat qiling.', 'Обратитесь в многофункциональный центр.'),
('hujjatlar_b1', 'B1', 12, 'Men soliq identifikatsiya raqamini oldim.', 'Я получил идентификационный номер налогоплательщика.'),
('hujjatlar_b1', 'B1', 13, 'Tibbiy ma’lumotnoma talab qilinadi.', 'Требуется медицинская справка.'),
('hujjatlar_b1', 'B1', 14, 'Hujjatlarni qabul qilish muddati bir oy. – Срок приёма документов', 'один месяц.'),
('hujjatlar_b1', 'B1', 15, 'Men elektron raqamli imzoga ega bo‘ldim.', 'Я получил электронную цифровую подпись.'),
('hujjatlar_b1', 'B1', 16, 'Notarius hujjatni tasdiqlashdan oldin shaxsimni tekshirdi.', 'Нотариус проверил мою личность перед заверением документа.'),
('hujjatlar_b1', 'B1', 17, 'Sud qarorining nusxasini olish kerak.', 'Нужно получить копию судебного решения.'),
('hujjatlar_b1', 'B1', 18, 'Hujjatlarni pochta orqali yuborish mumkin.', 'Документы можно отправить по почте.'),
('hujjatlar_b1', 'B1', 19, 'Mening arizam rad etildi, sababi noto‘liq ma’lumot.', 'Моё заявление отклонили из-за неполной информации.'),
('hujjatlar_b1', 'B1', 20, 'Shartnomani diqqat bilan o‘qing, imzolashdan oldin.', 'Внимательно прочитайте договор перед подписанием.'),
('pul_xarajat_b1', 'B1', 1, 'Oyiga qancha pul sarflaysiz?', 'Сколько денег вы тратите в месяц?'),
('pul_xarajat_b1', 'B1', 2, 'Tejamkorlik qilish muhim.', 'Важно экономить.'),
('pul_xarajat_b1', 'B1', 3, 'Kredit olishdan oldin o‘ylab ko‘ring.', 'Прежде чем брать кредит, подумайте.'),
('pul_xarajat_b1', 'B1', 4, 'Nima uchun bu qadar qimmat?', 'Почему это так дорого?'),
('pul_xarajat_b1', 'B1', 5, 'Men byudjetni rejalashtiraman.', 'Я планирую бюджет.'),
('pul_xarajat_b1', 'B1', 6, 'Oylik daromadim xarajatlarimni qoplaydi.', 'Мой месячный доход покрывает расходы.'),
('pul_xarajat_b1', 'B1', 7, 'Men har oy jamg‘arma hisobiga pul qo‘yaman.', 'Каждый месяц кладу деньги на сберегательный счёт.'),
('pul_xarajat_b1', 'B1', 8, 'Kutilmagan xarajatlar byudjetni buzdi.', 'Непредвиденные расходы нарушили бюджет.'),
('pul_xarajat_b1', 'B1', 9, 'Men pulni uch qismga ajrataman: majburiy, ixtiyoriy, jamg‘arma.', 'Я делю деньги на три части: обязательную, произвольную, сбережения.'),
('pul_xarajat_b1', 'B1', 10, 'Kredit kartadan foydalanish qulay, lekin qarzdorlikka olib kelishi mumkin.', 'Пользоваться кредитной картой удобно, но это может привести к задолженности.'),
('pul_xarajat_b1', 'B1', 11, 'Men naqd pulni afzal ko‘raman, karta emas.', 'Я предпочитаю наличные, а не карту.'),
('pul_xarajat_b1', 'B1', 12, 'Inflyatsiya tufayli pul qadrsizlanmoqda.', 'Из-за инфляции деньги обесцениваются.'),
('pul_xarajat_b1', 'B1', 13, 'U juda isrofgarchilik qiladi.', 'Он очень расточителен.'),
('pul_xarajat_b1', 'B1', 14, 'Oziq-ovqat eng katta xarajat moddasi. – Продукты питания', 'самая большая статья расходов.'),
('pul_xarajat_b1', 'B1', 15, 'Biz umumiy byudjetni yuritamiz.', 'Мы ведём общий бюджет.'),
('pul_xarajat_b1', 'B1', 16, 'Qarz berishdan oldin odamni yaxshi bilish kerak.', 'Прежде чем давать в долг, нужно хорошо знать человека.'),
('pul_xarajat_b1', 'B1', 17, 'Pulni qanday qilib oqilona sarflashni bilaman.', 'Я умею разумно тратить деньги.'),
('pul_xarajat_b1', 'B1', 18, 'Men bir yil ichida mashina sotib olish uchun pul yig‘moqchiman.', 'Хочу накопить деньги на покупку машины в течение года.'),
('pul_xarajat_b1', 'B1', 19, 'Moliyaviy maslahatchiga murojaat qilish foydali.', 'Полезно обратиться к финансовому консультанту.'),
('pul_xarajat_b1', 'B1', 20, 'Kambag‘allik va boylik – bu ko‘pincha odatlar masalasi. – Бедность и богатство', 'это часто вопрос привычек.'),
('media_b1', 'B1', 1, 'Siz qaysi yangilik kanalini tomosha qilasiz?', 'Какой новостной канал вы смотрите?'),
('media_b1', 'B1', 2, 'Internetda ko‘p yolg‘on ma’lumotlar bor.', 'В интернете много ложной информации.'),
('media_b1', 'B1', 3, 'Bu video juda ko‘p ko‘rilgan.', 'Это видео набрало много просмотров.'),
('media_b1', 'B1', 4, 'Gazetaga obuna bo‘lish arzon.', 'Подписка на газету дешёвая.'),
('media_b1', 'B1', 5, 'Men faqat ishonchli manbalarni o‘qiyman.', 'Я читаю только надёжные источники.'),
('media_b1', 'B1', 6, 'Haftalik jurnal chiqariladi.', 'Выпускается еженедельный журнал.'),
('media_b1', 'B1', 7, 'Yangiliklar ko‘pincha salbiy bo‘ladi.', 'Новости часто бывают негативными.'),
('media_b1', 'B1', 8, 'Men ertalab radio tinglayman.', 'Я слушаю радио утром.'),
('media_b1', 'B1', 9, 'U televidenieda ishlaydi.', 'Он работает на телевидении.'),
('media_b1', 'B1', 10, 'Siyosiy yangiliklar meni charchatadi.', 'Политические новости меня утомляют.'),
('media_b1', 'B1', 11, 'Ijtimoiy tarmoqlarda tezkor yangiliklar tarqaladi.', 'В соцсетях быстро распространяются новости.'),
('media_b1', 'B1', 12, 'Men kanalga obuna bo‘ldim va bildirishnomalarni yoqdim.', 'Я подписался на канал и включил уведомления.'),
('media_b1', 'B1', 13, 'Ushbu xabar hali tasdiqlanmagan.', 'Это сообщение ещё не подтверждено.'),
('media_b1', 'B1', 14, 'Ko‘plab odamlar sarlavhani o‘qib, mazmuniga e’tibor bermaydi.', 'Многие люди читают заголовок, не обращая внимания на содержание.'),
('media_b1', 'B1', 15, 'Men hujjatli filmlarni tomosha qilishni yaxshi ko‘raman.', 'Я люблю смотреть документальные фильмы.'),
('media_b1', 'B1', 16, 'Bugungi gazetada qiziqarli maqola bor.', 'В сегодняшней газете есть интересная статья.'),
('media_b1', 'B1', 17, 'Yangiliklar yig‘ilishida asosiy mavzular muhokama qilinadi.', 'На планерке обсуждаются главные темы.'),
('media_b1', 'B1', 18, 'U yangiliklarni har kuni ertalab ko‘rib chiqadi.', 'Он просматривает новости каждое утро.'),
('media_b1', 'B1', 19, 'Media savodxonlikni rivojlantirish kerak.', 'Нужно развивать медиаграмотность.'),
('media_b1', 'B1', 20, 'Bu telekanal xolis deb hisoblanadi.', 'Этот телеканал считается объективным.'),
('dostlar_munosabat_b1', 'B1', 1, 'Haqiqiy do‘st qiyin paytda yordam beradi.', 'Настоящий друг помогает в трудную минуту.'),
('dostlar_munosabat_b1', 'B1', 2, 'Biz bolalikdan do‘stmiz.', 'Мы дружим с детства.'),
('dostlar_munosabat_b1', 'B1', 3, 'U bilan har hafta uchrashamiz.', 'Мы встречаемся с ним каждую неделю.'),
('dostlar_munosabat_b1', 'B1', 4, 'Do‘stlikka vaqt kerak.', 'Для дружбы нужно время.'),
('dostlar_munosabat_b1', 'B1', 5, 'Kechirimlilik munosabatlarni saqlaydi.', 'Умение прощать сохраняет отношения.'),
('dostlar_munosabat_b1', 'B1', 6, 'Do‘stlarimga ishonaman.', 'Я доверяю своим друзьям.'),
('dostlar_munosabat_b1', 'B1', 7, 'U yaxshi do‘st, lekin ba’zida xudbin.', 'Он хороший друг, но иногда эгоистичен.'),
('dostlar_munosabat_b1', 'B1', 8, 'Biz bir-birimizga sirlarimizni aytamiz.', 'Мы рассказываем друг другу свои секреты.'),
('dostlar_munosabat_b1', 'B1', 9, 'Uzoq masofali do‘stlikni saqlash qiyin.', 'Трудно поддерживать дружбу на расстоянии.'),
('dostlar_munosabat_b1', 'B1', 10, 'Men yangi do‘stlar orttirishga ochiqman.', 'Я открыт для приобретения новых друзей.'),
('dostlar_munosabat_b1', 'B1', 11, 'U do‘stlari oldida meni kamsitdi.', 'Он унизил меня перед друзьями.'),
('dostlar_munosabat_b1', 'B1', 12, 'Do‘stlar bilan vaqt o‘tkazish meni quvontiradi.', 'Время с друзьями меня радует.'),
('dostlar_munosabat_b1', 'B1', 13, 'U meni hech qachon tushunmaydi.', 'Он никогда меня не понимает.'),
('dostlar_munosabat_b1', 'B1', 14, 'Ishonch buzilganda munosabatlarni tiklash mushkul.', 'Когда доверие нарушено, восстановить отношения трудно.'),
('dostlar_munosabat_b1', 'B1', 15, 'Eng yaxshi do‘stim – onam. – Мой лучший друг', 'мама.'),
('dostlar_munosabat_b1', 'B1', 16, 'U bilan birga ishlaymiz, shuning uchun ko‘p vaqt birgamiz.', 'Мы работаем вместе, поэтому много времени проводим вместе.'),
('dostlar_munosabat_b1', 'B1', 17, 'Men do‘stlarimga yordam berishdan mamnunman.', 'Я рад помогать своим друзьям.'),
('dostlar_munosabat_b1', 'B1', 18, 'Ba’zi do‘stliklar faqat bir mavsumga mo‘ljallangan.', 'Некоторые дружбы длятся только один сезон.'),
('dostlar_munosabat_b1', 'B1', 19, 'U doim sodiq va ishonchli.', 'Он всегда верный и надёжный.'),
('dostlar_munosabat_b1', 'B1', 20, 'Do‘stsiz hayot zerikarli.', 'Жизнь без друзей скучна.'),
('kundalik_muammo_b1', 'B1', 1, 'Iltimos, ovozingizni pasaytiring.', 'Пожалуйста, сделайте потише.'),
