('iqtisod_b2', 'B2', 20, 'Moliyaviy savodxonlik iqtisodiy farovonlikka olib keladi.', 'Финансовая грамотность ведёт к экономическому благополучию.'),
('argument_b2', 'B2', 1, 'Birinchidan, ikkinchidan, uchinchidan…', 'Во-первых, во-вторых, в-третьих…'),
('argument_b2', 'B2', 2, 'Keling, bunga boshqa tomondan qaraylik.', 'Давайте посмотрим на это с другой стороны.'),
('argument_b2', 'B2', 3, 'Misollar bilan tushuntirish osonroq.', 'Объяснять на примерах легче.'),
('argument_b2', 'B2', 4, 'Bu fikrga qarshi dalil keltiraman.', 'Приведу контраргумент к этому мнению.'),
('argument_b2', 'B2', 5, 'Xulosa qilib aytganda, men quyidagini taklif qilaman.', 'Подводя итог, я предлагаю следующее.'),
('argument_b2', 'B2', 6, 'Agar shart bajarilsa, unda natija…', 'Если условие выполнено, то результат…'),
('argument_b2', 'B2', 7, 'Buning aksi ham to‘g‘ri.', 'Верно и обратное.'),
('argument_b2', 'B2', 8, 'Sabab-oqibat zanjirini tahlil qilaylik.', 'Проанализируем причинно-следственную цепочку.'),
('argument_b2', 'B2', 9, 'Ushbu tezisni isbotlash uchun yetarli asoslar mavjud.', 'Для доказательства этого тезиса есть достаточные основания.'),
('argument_b2', 'B2', 10, 'Hech kim bu borada aniq javob bera olmaydi.', 'Никто не может дать точный ответ на этот счёт.'),
('argument_b2', 'B2', 11, 'Sizning argumentingiz o‘rinli, lekin yetarli emas.', 'Ваш аргумент уместен, но недостаточен.'),
('argument_b2', 'B2', 12, 'Keling, analogiyadan foydalanaylik.', 'Давайте воспользуемся аналогией.'),
('argument_b2', 'B2', 13, 'Bu deduksiya yoki induksiya usuli bilan isbotlanishi mumkin.', 'Это можно доказать методом дедукции или индукции.'),
('argument_b2', 'B2', 14, 'Bahsli jihatlarini alohida ko‘rib chiqish kerak.', 'Спорные аспекты нужно рассмотреть отдельно.'),
('argument_b2', 'B2', 15, 'Men sizning mantiqingizni kuzatib bormoqdaman.', 'Я слежу за вашей логикой.'),
('argument_b2', 'B2', 16, 'Ushbu dalilni rad etish mumkin, chunki…', 'Этот довод можно опровергнуть, потому что…'),
('argument_b2', 'B2', 17, 'Siz o‘zingizga zid gapiryapsiz.', 'Вы говорите противоречиво.'),
('argument_b2', 'B2', 18, 'Eng ishonchli dalil – bu amaliyot. – Самый убедительный довод', 'это практика.'),
('argument_b2', 'B2', 19, 'Keling, umumlashtirishdan saqlanaylik.', 'Давайте избегать обобщений.'),
('argument_b2', 'B2', 20, 'Mantiqiy xulosaga kelish uchun barcha omillarni hisobga olish kerak.', 'Чтобы прийти к логическому выводу, нужно учесть все факторы.'),
('muammo_chuqur_b2', 'B2', 1, 'Muammoning ildiziga borish kerak.', 'Нужно добраться до корня проблемы.'),
('muammo_chuqur_b2', 'B2', 2, 'Qisqa muddatli va uzoq muddatli choralar farqlanadi.', 'Краткосрочные и долгосрочные меры различаются.'),
('muammo_chuqur_b2', 'B2', 3, 'Hech qanday yechim mukammal emas.', 'Ни одно решение не идеально.'),
('muammo_chuqur_b2', 'B2', 4, 'Oldini olish bartaraf qilishdan yaxshiroq.', 'Предотвращение лучше, чем устранение.'),
('muammo_chuqur_b2', 'B2', 5, 'Hamkorlikda ishlash samaraliroq.', 'Работать в сотрудничестве эффективнее.'),
('muammo_chuqur_b2', 'B2', 6, 'Tizimli muammo tizimli yechim talab qiladi.', 'Системная проблема требует системного решения.'),
('muammo_chuqur_b2', 'B2', 7, 'Inson omili ko‘pincha asosiy to‘siq bo‘ladi.', 'Человеческий фактор часто является основным препятствием.'),
('muammo_chuqur_b2', 'B2', 8, 'Biz muammoni qayta tavsiflashimiz kerak.', 'Нам нужно переформулировать проблему.'),
('muammo_chuqur_b2', 'B2', 9, 'Resurslar cheklangan, shuning uchun ustuvorliklarni belgilang.', 'Ресурсы ограничены, поэтому определите приоритеты.'),
('muammo_chuqur_b2', 'B2', 10, 'Keng qamrovli tahlildan so‘ng harakat rejasini tuzish mumkin.', 'После всестороннего анализа можно составить план действий.'),
('muammo_chuqur_b2', 'B2', 11, 'Ba’zida eng yaxshi yechim – hech narsa qilmaslik. – Иногда лучшее решение', 'ничего не делать.'),
('muammo_chuqur_b2', 'B2', 12, 'Ehtimollarni baholash va risklarni minimallashtirish lozim.', 'Нужно оценить вероятности и минимизировать риски.'),
('muammo_chuqur_b2', 'B2', 13, 'Muammoning salbiy ta’sirini kvantifikatsiya qilish mumkinmi?', 'Можно ли квантифицировать негативное влияние проблемы?'),
('muammo_chuqur_b2', 'B2', 14, 'Yechimlarni sinovdan o‘tkazish uchun pilot loyiha boshlang.', 'Запустите пилотный проект для тестирования решений.'),
('muammo_chuqur_b2', 'B2', 15, 'Qaror qabul qilishda axloqiy jihatlarni hisobga oling.', 'При принятии решения учитывайте этические аспекты.'),
('muammo_chuqur_b2', 'B2', 16, 'Muvaffaqiyatsiz yechimlar ham qimmatli saboq beradi.', 'Неудачные решения тоже дают ценный урок.'),
('muammo_chuqur_b2', 'B2', 17, 'Monokauzal fikrlashdan uzoqlashing.', 'Отойдите от монокаузального мышления.'),
('muammo_chuqur_b2', 'B2', 18, 'Teskari aloqa mexanizmini o‘rnatish muhim.', 'Важно настроить механизм обратной связи.'),
('muammo_chuqur_b2', 'B2', 19, 'Vaqt o‘tishi bilan yechimni qayta ko‘rib chiqish kerak bo‘lishi mumkin.', 'Со временем решение может потребовать пересмотра.'),
('muammo_chuqur_b2', 'B2', 20, 'Eng qiyin muammolar ko‘pincha eng oddiy yechimlarga ega.', 'Самые сложные проблемы часто имеют самые простые решения.'),
('maqsad_reja_b2', 'B2', 1, 'Men aniq va o‘lchovli maqsadlarni qo‘yaman.', 'Я ставлю конкретные и измеримые цели.'),
('maqsad_reja_b2', 'B2', 2, 'Kelgusi besh yil ichida uy sotib olmoqchiman.', 'В ближайшие пять лет я хочу купить квартиру.'),
('maqsad_reja_b2', 'B2', 3, 'Rejani bosqichma-bosqich amalga oshirish kerak.', 'План нужно выполнять поэтапно.'),
('maqsad_reja_b2', 'B2', 4, 'To‘siqlarga qaramay, maqsadimdan qaytmayman.', 'Несмотря на препятствия, я не отступлю от цели.'),
('maqsad_reja_b2', 'B2', 5, 'Muvaffaqiyatga erishish uchun intizim zarur.', 'Для достижения успеха необходима дисциплина.'),
('maqsad_reja_b2', 'B2', 6, 'Men har kuni kichik qadamlar bilan maqsadimga yaqinlashaman.', 'Каждый день маленькими шагами приближаюсь к своей цели.'),
('maqsad_reja_b2', 'B2', 7, 'Uzoq muddatli maqsadlarni qisqa muddatli vazifalarga bo‘lish mumkin.', 'Долгосрочные цели можно разбить на краткосрочные задачи.'),
('maqsad_reja_b2', 'B2', 8, 'Men o‘z maqsadlarimni yozib qo‘yaman va ularni muntazam ko‘rib chiqaman.', 'Я записываю свои цели и регулярно их пересматриваю.'),
('maqsad_reja_b2', 'B2', 9, 'Ba’zida maqsadlarni o‘zgartirish yoki kechiktirish kerak bo‘ladi.', 'Иногда цели нужно менять или откладывать.'),
('maqsad_reja_b2', 'B2', 10, 'Motivatsiya pasayganda, kichik yutuqlarni nishonlang.', 'Когда мотивация падает, отмечайте маленькие достижения.'),
('maqsad_reja_b2', 'B2', 11, 'Muvaffaqiyatga erishganlardan o‘rganish foydali.', 'Полезно учиться у тех, кто достиг успеха.'),
('maqsad_reja_b2', 'B2', 12, 'Men o‘zimning kuchli tomonlarimga tayanib maqsad qo‘yaman.', 'Я ставлю цели, опираясь на свои сильные стороны.'),
('maqsad_reja_b2', 'B2', 13, 'Rejani amalga oshirishda vaqtni boshqarish muhim.', 'При выполнении плана важно тайм-менеджмент.'),
('maqsad_reja_b2', 'B2', 14, 'Kutilmagan holatlar uchun zaxira reja tuzish kerak.', 'Нужно составить запасной план на случай непредвиденных обстоятельств.'),
('maqsad_reja_b2', 'B2', 15, 'Maqsadlar nafaqat moddiy, balki ma’naviy ham bo‘lishi mumkin.', 'Цели могут быть не только материальными, но и духовными.'),
('maqsad_reja_b2', 'B2', 16, 'Men har oy maqsadlarimga erishish darajasini baholayman.', 'Каждый месяц я оцениваю степень достижения своих целей.'),
('maqsad_reja_b2', 'B2', 17, 'Yomon odatlar maqsadlarga erishishga to‘sqinlik qiladi.', 'Вредные привычки мешают достижению целей.'),
('maqsad_reja_b2', 'B2', 18, 'Maqsadsiz hayot kemasiz dengizda suzishga o‘xshaydi.', 'Жизнь без цели похожа на плавание в море без корабля.'),
('maqsad_reja_b2', 'B2', 19, 'Men o‘z maqsadlarimni boshqalar bilan baham ko‘raman, bu meni mas’uliyatli qiladi.', 'Я делюсь своими целями с другими, это делает меня ответственным.'),
('maqsad_reja_b2', 'B2', 20, 'Eng muhimi – harakatni boshlash. – Самое главное', 'начать действовать.'),
('debat_b2', 'B2', 1, 'Sizning fikringiz bilan bahslashishga majburman.', 'Я вынужден не согласиться с вашим мнением.'),
('debat_b2', 'B2', 2, 'Iltimos, fikringizni isbotlovchi misol keltiring.', 'Пожалуйста, приведите пример, доказывающий вашу мысль.'),
('debat_b2', 'B2', 3, 'Bu mantiqiy xatolik.', 'Это логическая ошибка.'),
('debat_b2', 'B2', 4, 'Keling, mavzuga qaytaylik.', 'Давайте вернёмся к теме.'),
('debat_b2', 'B2', 5, 'Sizni tushunaman, lekin siz bir faktni e’tiborsiz qoldiryapsiz.', 'Я вас понимаю, но вы упускаете один факт.'),
('debat_b2', 'B2', 6, 'Sizning asosiy tezisingiz nimaga asoslangan?', 'На чём основан ваш основной тезис?'),
('debat_b2', 'B2', 7, 'Bu strawman argumenti (qo‘g‘irchoq) – siz mening pozitsiyamni buzib ko‘rsatyapsiz. – Это соломенное чучело', 'вы искажаете мою позицию.'),
('debat_b2', 'B2', 8, 'Keling, so‘z o‘yinlaridan emas, dalillarga tayanaylik.', 'Давайте опираться на факты, а не на игру слов.'),
('debat_b2', 'B2', 9, 'Men sizning fikringizni qabul qilishdan oldin qo‘shimcha dalillarni kutaman.', 'Прежде чем принять ваше мнение, я жду дополнительных доказательств.'),
('debat_b2', 'B2', 10, 'Sizning argumentingizda noaniqlik bor.', 'В вашем аргументе есть неясность.'),
('debat_b2', 'B2', 11, 'Keling, bir-birimizni tinglaylik, faqat gapirmaylik.', 'Давайте слушать друг друга, а не только говорить.'),
('debat_b2', 'B2', 12, 'Siz juda emotsional munosabat bildiryapsiz.', 'Вы реагируете слишком эмоционально.'),
('debat_b2', 'B2', 13, 'Men sizning nuqtai nazaringizni qabul qilaman, ammo xulosa chiqarishga shoshilmang.', 'Я принимаю вашу точку зрения, но не торопитесь с выводами.'),
('debat_b2', 'B2', 14, 'Bu false dilemma (noto‘g‘ri ikkilamchilik) – boshqa variantlar ham bor. – Это ложная дилемма', 'есть и другие варианты.'),
('debat_b2', 'B2', 15, 'Sizning dalilingiz statistik jihatdan ahamiyatsiz.', 'Ваш довод статистически незначим.'),
('debat_b2', 'B2', 16, 'Men rais sifatida so‘zni boshqa ishtirokchiga beraman.', 'Как председатель, я передаю слово другому участнику.'),
('debat_b2', 'B2', 17, 'Vaqtimiz cheklangan, keling, eng muhim nuqtalarga e’tibor qarataylik.', 'Время ограничено, давайте сосредоточимся на самых важных пунктах.'),
('debat_b2', 'B2', 18, 'Sizning pozitsiyangizda bir qancha zaif tomonlar bor.', 'В вашей позиции есть несколько слабых мест.'),
('debat_b2', 'B2', 19, 'Men siz bilan to‘liq bahslashmayman, lekin kichik bir tafsilotda farqimiz bor.', 'Я не полностью спорю с вами, но у нас есть различие в одной детали.'),
('debat_b2', 'B2', 20, 'Bahs davomida shaxsiyatga emas, mavzuga e’tibor qarataylik.', 'В ходе дискуссии давайте сосредоточимся на теме, а не на личности.'),
('rivojlanish_b2', 'B2', 1, 'Uzluksiz ta’lim zamon talabi. – Непрерывное образование', 'требование времени.'),
('rivojlanish_b2', 'B2', 2, 'O‘z ustida ishlash hech qachon to‘xtamasligi kerak.', 'Работа над собой не должна прекращаться.'),
('rivojlanish_b2', 'B2', 3, 'Mentor yoki murabbiy topish foydali.', 'Полезно найти наставника или тренера.'),
('rivojlanish_b2', 'B2', 4, 'Xatolardan o‘rganish rivojlanishning bir qismi. – Учиться на ошибках', 'часть развития.'),
('rivojlanish_b2', 'B2', 5, 'Bugun juda ko‘p bepul ta’lim resurslari bor.', 'Сегодня есть много бесплатных образовательных ресурсов.'),
('rivojlanish_b2', 'B2', 6, 'Men har kuni kamida 30 daqiqa o‘qishga ajrataman.', 'Я выделяю на чтение минимум 30 минут каждый день.'),
('rivojlanish_b2', 'B2', 7, 'Onlayn kurslar orqali yangi kasb o‘rganish mumkin.', 'Через онлайн-курсы можно освоить новую профессию.'),
('rivojlanish_b2', 'B2', 8, 'Tez o‘zgaruvchan dunyoda moslashuvchanlik muhim.', 'В быстро меняющемся мире важна адаптивность.'),
('rivojlanish_b2', 'B2', 9, 'Men o‘rganish uslubimni (vizual, eshitish, kinestetik) bilaman.', 'Я знаю свой стиль обучения (визуальный, аудиальный, кинестетический).'),
('rivojlanish_b2', 'B2', 10, 'Kechqurun o‘rganilgan materialni takrorlash yaxshi esda qoladi.', 'Повторение изученного материала вечером помогает лучше запомнить.'),
('rivojlanish_b2', 'B2', 11, 'O‘z-o‘zini baholash rivojlanishning muhim qismi. – Самооценка', 'важная часть развития.'),
('rivojlanish_b2', 'B2', 12, 'Men maqsadli ravishda zaif tomonlarimni kuchaytiryapman.', 'Я целенаправленно усиливаю свои слабые стороны.'),
('rivojlanish_b2', 'B2', 13, 'Guruhda o‘rganish individual o‘rganishdan farq qiladi.', 'Обучение в группе отличается от индивидуального.'),
('rivojlanish_b2', 'B2', 14, 'Chet tilini o‘rganishda muntazamlik muhim.', 'В изучении иностранного языка важна регулярность.'),
('rivojlanish_b2', 'B2', 15, 'Men o‘qiganlarimni amalda qo‘llashga harakat qilaman.', 'Стараюсь применять изученное на практике.'),
('rivojlanish_b2', 'B2', 16, 'Kreativ fikrlashni rivojlantirish mumkin.', 'Креативное мышление можно развить.'),
('rivojlanish_b2', 'B2', 17, 'O‘rganish motivatsiyasi tashqi va ichki omillarga bog‘liq.', 'Мотивация к обучению зависит от внешних и внутренних факторов.'),
('rivojlanish_b2', 'B2', 18, 'Men o‘z bilimlarimni boshqalarga o‘rgatish orqali mustahkamlayman.', 'Я укрепляю свои знания, обучая других.'),
('rivojlanish_b2', 'B2', 19, 'Rivojlanish uchun qulay muhit yaratish kerak.', 'Для развития нужно создать благоприятную среду.'),
('rivojlanish_b2', 'B2', 20, 'Eng yaxshi sarmoya – bu o‘zingizga qilgan sarmoya. – Лучшая инвестиция', 'это инвестиция в себя.'),
('madaniyat_b2', 'B2', 1, 'Har bir millatning o‘ziga xos urf-odatlari bor.', 'У каждого народа есть свои обычаи.'),
('madaniyat_b2', 'B2', 2, 'An’analarni saqlash kelajak avlod uchun muhim.', 'Сохранять традиции важно для будущих поколений.'),
('madaniyat_b2', 'B2', 3, 'Bayramlar odamlarni birlashtiradi.', 'Праздники объединяют людей.'),
('madaniyat_b2', 'B2', 4, 'Madaniyatlararo muloqot dunyoqarashni kengaytiradi.', 'Межкультурное общение расширяет кругозор.'),
('madaniyat_b2', 'B2', 5, 'Biz o‘zbek mehmondo‘stligi bilan faxrlanamiz.', 'Мы гордимся узбекским гостеприимством.'),
('madaniyat_b2', 'B2', 6, 'Navro‘z – bahor bayrami va yangi yil boshlanishi. – Навруз', 'весенний праздник и начало нового года.'),
('madaniyat_b2', 'B2', 7, 'To‘ylarda ko‘plab milliy taomlar tortiladi.', 'На свадьбах подают много национальных блюд.'),
('madaniyat_b2', 'B2', 8, 'Katta yoshlilarni hurmat qilish – bizning an’anamiz. – Уважение к старшим', 'наша традиция.'),
('madaniyat_b2', 'B2', 9, 'Turli madaniyatlarda bir xil imo-ishoralar turlicha ma’noni anglatishi mumkin.', 'В разных культурах одни и те же жесты могут иметь разное значение.'),
('madaniyat_b2', 'B2', 10, 'Men o‘z madaniyatimni boshqalarga tanishtirishni yaxshi ko‘raman.', 'Мне нравится знакомить других со своей культурой.'),
('madaniyat_b2', 'B2', 11, 'Globalizatsiya ba’zi an’analarni yo‘qolish xavfiga olib keladi.', 'Глобализация приводит к риску исчезновения некоторых традиций.'),
('madaniyat_b2', 'B2', 12, 'Milliy liboslar – madaniy merosning bir qismi. – Национальные костюмы', 'часть культурного наследия.'),
('madaniyat_b2', 'B2', 13, 'Har bir mintaqaning o‘ziga xos qo‘shiq va raqslari bor.', 'У каждого региона есть свои песни и танцы.'),
('madaniyat_b2', 'B2', 14, 'Diniy urf-odatlar ham madaniyatning muhim tarkibiy qismi.', 'Религиозные обычаи также важная составляющая культуры.'),
('madaniyat_b2', 'B2', 15, 'Madaniy merosni saqlash uchun muzeylar va kutubxonalar muhim rol o‘ynaydi.', 'Для сохранения культурного наследия важную роль играют музеи и библиотеки.'),
('madaniyat_b2', 'B2', 16, 'Men boshqa madaniyat vakillari bilan suhbatlashishdan zavqlanaman.', 'Я получаю удовольствие от общения с представителями других культур.'),
('madaniyat_b2', 'B2', 17, 'An’analarni buzmaslik kerak, lekin ularni yangi davrga moslashtirish mumkin.', 'Нельзя нарушать традиции, но их можно адаптировать к новой эпохе.'),
('madaniyat_b2', 'B2', 18, 'Ota-ona va bobokalonlarning hayotiy hikmatlari avloddan-avlodga o‘tadi.', 'Житейская мудрость родителей и предков передаётся из поколения в поколение.'),
('madaniyat_b2', 'B2', 19, 'Madaniyat – bu jamiyatning ruhi. – Культура', 'это душа общества.'),
